import subprocess

# Function to generate requirements.txt with hashes
def generate_requirements_hash():
    subprocess.run(["pip", "freeze", "--all", "--out", "requirements.txt"])

# Function to update requirements.txt with hashes
def update_requirements_hash():
    subprocess.run(["pip", "install", "-r", "requirements.txt", "--upgrade", "--hash"])

# Function to generate Poetry lock file
def generate_poetry_lock():
    subprocess.run(["poetry", "lock", "--no-dev"])

# Function to update Poetry lock file
def update_poetry_lock():
    subprocess.run(["poetry", "update", "--lock"])

# Function to check for consistency between requirements.txt and Poetry lock files
def check_consistency():
    subprocess.run(["pip", "hash", "requirements.txt"], check=True)
    subprocess.run(["poetry", "hash"], check=True)

# Usage
generate_requirements_hash()
update_requirements_hash()
generate_poetry_lock()
update_poetry_lock()
check_consistency()